#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int a[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &a[i]);
        }
        int ans = 0;
        for (int i = 0; i < N / 2; i++) {
            if ((a[i] > a[N - i - 1] && a[i] < a[N - i - 2]) || (a[i] < a[N - i - 1] && a[i] > a[N - i - 2])) {
                ans++;
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

