import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] a = new int[N];
            for (int i = 0; i < N; i++) {
                a[i] = sc.nextInt();
            }
            int ans = 0;
            for (int i = 0; i < N / 2; i++) {
                if ((a[i] > a[N - i - 1] && a[i] < a[N - i - 2]) || (a[i] < a[N - i - 1] && a[i] > a[N - i - 2])) {
                    ans++;
                }
            }
            System.out.println(ans);
        }
    }
}

